var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"어떻게 된 거야! 학회에서 보낸 감찰관까지 당해 버렸잖아!","JPN":"どうなってんだ！　学会から送られてきた監察官までやられたじゃないか！","ENG":"What happened?! She even took out the Society's inspector!","TWN":"怎麼搞的！連學會派來的監察委員也打輸她！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"제길……. 연락도 없이 갑자기 쳐들어온 걸 어떻게 잘 꼬드긴 줄 알았는데…….","JPN":"くそ……前触れもなく来やがったやつをうまく焚きつけたと思ったら……","ENG":"Damn it… I thought the inspector might have managed to talk that brat out of barging in here…","TWN":"該死的……還想說怎麼知道要慫恿她突然闖進來……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"감찰관이면 최소한 공멸이라도 했어야 하는 거 아냐! 어?!","JPN":"監察官なら道連れにしてでも始末するべきだろ！！","ENG":"The least she could do is take down that brat with her! I mean, come on!","TWN":"身為監察委員，打不贏至少也要玉石俱焚吧？！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"다행인 줄 알지? 저 여자가 안 당했으면 대표님 정수리에 말뚝이 꽂혔을 텐데?","JPN":"贅沢言わないでよ。あの女がやられてなかったら、今頃代表の頭に杭が刺さるところだったわよ？","ENG":"You should consider yourself lucky. If Horizon hadn't taken out that woman, she would've driven a stake in your forehead.","TWN":"你要慶幸吧？如果她沒事，那就換你有事了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"다 안다는 듯이 지껄이지 마!!","JPN":"偉そうに知った風な口を利くな！","ENG":"You don't know what you're talking about!!","TWN":"少在那邊給我說風涼話！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"여태까지 저 사채꾼 하나한테 카운터가 몇 명이나 달라 붙었는지 알아?!","JPN":"これまであの闇金野郎にカウンターが何人やられたと思ってんだ！？","ENG":"Do you have any idea how many Counters I threw at that loan shark?","TWN":"你知道到現在為止，派出多少制裁者，去對付那一個放高利貸的嗎？！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"3종 침식체가 아니라 4종 침식체여도 벌써 지쳐 나가떨어졌을 거라고!","JPN":"第3種侵食体どころか第4種侵食体でもくたばっておかしくないぐらいなんだぞ！","ENG":"It was enough to wear out a Category 3… no, even a Category 4!","TWN":"而且不是3類侵蝕體喔，連4類侵蝕體也疲於應付！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흐음. 대표님, 참 머리가 나쁘구나.","JPN":"ふーん、代表って実は頭悪いのね。","ENG":"Hmm... You're really dense, aren't you boss?","TWN":"嗯嗯，代表你的腦袋真的很不好欸～"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"다시 한 번 지껄여 봐라. 그라운드 원에서 대학원까지 나왔던 나한테 뭐라고?","JPN":"もう一度ほざいてみろ。グラウンド・ワンで大学院まで卒業した俺に向かってなんだと？","ENG":"I dare you to say that again. I happen to have a master's degree from Ground One! How dare you?","TWN":"你說話給我放尊重點！我可是從G1的研究所畢業的？！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"건방지게 굴어도 그냥 넘어가 주니 내가 우습게 보이나! 어?!","JPN":"生意気に振舞っても見逃してやってるから、僕のことなめてんのか！　ああ！？","ENG":"Do you take me for a fool just because I've been so lenient with your insolence?! Huh?!","TWN":"你之前在那邊沒大沒小的，我都沒跟你計較，現在就不把我放眼裡是吧！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 이런 상황까지 와서 뭘 무게 잡고 그래.","JPN":"フフッ、こんな状況でそんなもったいぶってもね。","ENG":"Heh. It's a little late to demand respect at this point, don't you think?","TWN":"呵呵～都這種時候了，還在那耍什麼威風？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"대표님은 학회에 한 번 발을 들인 주제에 3종이네, 4종이네 <color=#ffd34c>일반인</color> 같은 발상에 얽매여 있잖아?","JPN":"代表も一応とはいえ学会に足を踏み入れたのに、第3種だの第4種だの<color=#ffd34c>一般人</color>みたいな発想にとらわれているじゃない。","ENG":"You've been to the Society only once, and yet you still remain wrapped up in concepts like Category 3 or Category 4, just like the rest of the <color=#ffd34c>mortals</color>.","TWN":"你明明就去過學會，卻還在那邊3類、4類的，跟那些沒見過世面的<color=#ffd34c>市井小民</color>一樣？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"이……. 학회가 아니면 현실에 있지도 못할 버러지 그림자 주제에……!","JPN":"貴様……学会がなかったら現実に存在すらできない虫けら同然のシャドウのくせに……！","ENG":"You… You're nothing but a third rate Shadow who couldn't exist on this plane if it weren't for the Society!","TWN":"你……要是沒有學會，你們這些暗影有辦法留在現世嗎……！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"아, 우리가 학회에 의탁한 걸 여태 그렇게 이해하고 있었어?","JPN":"あ、私たちが学会に依託していることをそういう感じで理解してたの？","ENG":"Oh, is that how you understood our relationship with the Society?","TWN":"喔～你一直以為我們依附在學會底下嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"미안하지만 완전히 잘못 짚었어, 대표님.","JPN":"悪いけど完全に見当違いだわ、代表。","ENG":"Sorry boss, but you've got it all wrong.","TWN":"很抱歉，可是天大的誤會喔，代表！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그리고 그 로봇은 대표님이 생각하는 것만큼 단순한 기계뭉치가 아냐.","JPN":"そして、あのロボットは代表が思っているほど単純な機械ではないわ。","ENG":"And that robot isn't just the simple machine you think she is either.","TWN":"還有，那個機器人並非如你所想的，只是個普通的機器。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"내 입장에서는 <color=#ffd34c>참 생각없이 건드렸네</color>랑 <color=#ffd34c>저런 거랑 엮이다니 운도 좋네</color>가 절반씩 섞인 느낌?","JPN":"個人的な感想で言えば、「<color=#ffd34c>後先考えずによく敵に回したわね</color>」と「<color=#ffd34c>あんなのに絡まれてなんてラッキーなの</color>」を半分ずつ混ぜた感じ、かな。","ENG":"The way I see it, you're somewhere between <color=#ffd34c>a fool who messed with something you can't handle</color> and <color=#ffd34c>a lucky bastard who managed to stumble upon a marvel</color>.","TWN":"我對於這件事的感想是，<color=#ffd34c>怎麼會這麼蠢去招惹她</color>，跟<color=#ffd34c>運氣這麼好，竟然和那種傢伙扯上邊</color>，這樣。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"……단순한 기계뭉치가 아니라고? 생각없이 건드렸어?","JPN":"……単純な機械じゃない？　後先考えず敵に回した？","ENG":"…It's not a simple machine? I've messed with more than I can handle, you say?","TWN":"……不是普通的機器？怎麼會這麼蠢去招惹她？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하! 하하!","JPN":"ハ！　アハハッ！","ENG":"Ha! Haha!","TWN":"哈！哈哈！！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"셰나, 그거야말로 너 같이 변변찮은 그림자가 할 생각이지.","JPN":"シェナ、それこそお前みたいなろくでなしのシャドウの考え方だろ。","ENG":"Oh, please Shena. Only a pathetic Shadow would think like that.","TWN":"世娜，像你這種三流的暗影才會這麼想！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"<color=#ffd34c>카메라</color>를 증폭시켜. 기술실에 증폭 장치가 과부하돼도 절대 멈추지 말라고 전해.","JPN":"<color=#ffd34c>カメラ</color>を増幅させろ。技術室には増幅装置が過負荷状態になっても絶対に止めるなと伝えろ。","ENG":"Amplify the <color=#ffd34c>camera</color>'s output. Tell the engineers to keep going even if the amplifier starts to overload.","TWN":"讓<color=#ffd34c>相機</color>增幅！去告訴技術室，就算超載也不准關掉增幅裝置！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"뒷일은 생각하고 내리는 지시야? 나야 이 도시가 어떻게든 되든 상관없지만서도?","JPN":"後のことを考えての指示なの？　私は別にこの都市がどうなっても構わないけど。","ENG":"Are you even thinking about the consequences? Though personally, I couldn't give a hoot what happens to this city.","TWN":"這是有考慮到後果的決定嗎？雖然這座城市會變怎樣，我個人是無所謂。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"흥. 그거야 호라이즌이 내 앞에 나타난 다음에 고민해도 돼.","JPN":"ふん、それはホライズンがここに現れた後で考えればいい。","ENG":"Hmph. It's not too late to worry about that after Horizon shows up.","TWN":"哼，這等到地平線出現在我面前後再考慮也不遲！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그러니 내기 하나 할까, 셰나? 그 사채꾼이 내 앞에 설 수 있을지?","JPN":"だから賭けをしよう、シェナ。あの闇金野郎が僕のところまで来られるかどうか。","ENG":"So how about a wager, Shena? Want to make a bet on if that loan shark can make it to me?","TWN":"世娜，要來打賭嗎？賭那個放高利貸的，能在我面前站得住嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"난 <color=#ffd34c>절대 안 된다</color>에 걸기로 하지.","JPN":"僕は<color=#ffd34c>絶対に来れない</color>に賭けよう。","ENG":"My money's on <color=#ffd34c>there's no way in hell</color> she can do that.","TWN":"我賭<color=#ffd34c>絕對不可能</color>！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"}]`);export{e as default};